// Runs once per email item - safe for multiple emails arriving at once
const emailItem = $('Get Email with Attachment').item.json;
const pdfItem = $('Extract PDF Text').item.json;

// With Simplify OFF, from/to/subject may be parsed objects
const rawSubject = emailItem.subject;
const subject = (typeof rawSubject === 'object' && rawSubject !== null) 
  ? (rawSubject.text || rawSubject.value || '') 
  : (rawSubject || '');

const rawFrom = emailItem.from;
const from = (typeof rawFrom === 'object' && rawFrom !== null) 
  ? (rawFrom.text || (rawFrom.value && rawFrom.value[0] ? rawFrom.value[0].name + ' <' + rawFrom.value[0].address + '>' : '')) 
  : (rawFrom || '');

const rawDate = emailItem.date;
const date = (typeof rawDate === 'object' && rawDate !== null) 
  ? (rawDate.text || String(rawDate)) 
  : (rawDate || '');

const snippet = emailItem.snippet || '';
const emailBody = emailItem.text || snippet;

const hasPdfError = !!pdfItem.error;
const pdfText = !hasPdfError ? (pdfItem.text || '') : '';

const contentToAnalyze = pdfText 
  ? '[PDF ATTACHMENT]\n' + pdfText 
  : '[EMAIL BODY]\n' + emailBody;

return {
  json: {
    email_id: emailItem.id || '',
    email_subject: subject,
    email_from: from,
    email_date: date,
    source: pdfText ? 'PDF Attachment' : 'Email Body',
    ai_input_text: 'Subject: ' + subject + '\nFrom: ' + from + '\nDate: ' + date + '\n\nContent:\n' + contentToAnalyze
  }
};

const items = $input.all();
const today = $now.toFormat('yyyy-MM-dd');

// Get yesterday's date for the morning summary
const yesterday = $now.minus({days: 1}).toFormat('yyyy-MM-dd');

// Filter for yesterday's processed invoices
const yesterdayRows = items.filter(i => i.json['Date Processed'] === yesterday);
// Also get today's in case some were processed after midnight
const todayRows = items.filter(i => i.json['Date Processed'] === today);
const allRecentRows = [...yesterdayRows, ...todayRows];

let msg;
if (allRecentRows.length === 0) {
  msg = '📋 <b>Invoice Daily Summary</b>\n';
  msg += '<i>' + today + '</i>\n\n';
  msg += 'No invoices processed since yesterday.';
} else {
  // Group totals by currency
  const byCurrency = {};
  const vendors = [];
  for (const row of allRecentRows) {
    const cur = row.json['Currency'] || 'Unknown';
    const amt = parseFloat(row.json['Total Amount']) || 0;
    byCurrency[cur] = (byCurrency[cur] || 0) + amt;
    vendors.push(row.json['Vendor'] || 'Unknown');
  }

  const totalsStr = Object.entries(byCurrency)
    .map(([cur, total]) => '  ' + cur + ' ' + total.toFixed(2))
    .join('\n');

  const vendorList = [...new Set(vendors)].map(v => '  • ' + v).join('\n');

  msg = '📋 <b>Invoice Daily Summary</b>\n';
  msg += '<i>' + today + '</i>\n\n';
  msg += '<b>Invoices processed:</b> ' + allRecentRows.length + '\n\n';
  msg += '<b>Totals:</b>\n' + totalsStr + '\n\n';
  msg += '<b>Vendors:</b>\n' + vendorList;
}

return [{ json: { message: msg, invoiceCount: allRecentRows.length } }];

